300→): Promise<OrphanedDecision[]> {
301→  const thresholdDate = new Date(
302→    Date.now() - COHERENCE_AGE_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
303→  );
304→
305→  const [rows] = await surreal.query<[OrphanedDecision[]]>(
306→    `SELECT id, summary, created_at FROM decision
307→     WHERE workspace = $ws
308→       AND status = "confirmed"
309→       AND created_at < $threshold
310→       AND array::len(<-implemented_by<-git_commit) = 0
311→       AND array::len(<-implemented_by<-pull_request) = 0
312→     ORDER BY created_at ASC
313→     LIMIT 50;`,
314→    { ws: workspaceRecord, threshold: thresholdDate },
315→  );
316→  return rows ?? [];
317→}
318→
319→/**
320→ * Finds active objectives older than the coherence threshold with no
321→ * supporting intents (via supports edges).
322→ */
323→export async function queryStaleObjectives(
324→  surreal: Surreal,
325→  workspaceRecord: RecordId<"workspace", string>,
326→): Promise<StaleObjective[]> {
327→  const thresholdDate = new Date(
328→    Date.now() - COHERENCE_AGE_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
329→  );
330→
331→  const [rows] = await surreal.query<[StaleObjective[]]>(
332→    `SELECT id, title, created_at FROM objective
333→     WHERE workspace = $ws
334→       AND status = "active"
335→       AND created_at < $threshold
336→       AND array::len(<-supports<-intent) = 0
337→     ORDER BY created_at ASC
338→     LIMIT 50;`,
339→    { ws: workspaceRecord, threshold: thresholdDate },
340→  );
341→  return rows ?? [];
342→}
343→
344→/**
345→ * Runs coherence scans: detects orphaned decisions and stale objectives,
346→ * creates observations for disconnected patterns.
347→ *
348→ * Deterministic -- no LLM filtering needed.
349→ */
350→export async function runCoherenceScans(
351→  surreal: Surreal,
352→  workspaceRecord: RecordId<"workspace", string>,
353→): Promise<CoherenceScanResult> {
354→  const result: CoherenceScanResult = {
355→    orphaned_decisions_found: 0,
356→    stale_objectives_found: 0,
357→    observations_created: 0,
358→  };
359→
360→  // Load existing observations for deduplication
361→  const existingObservations = await listWorkspaceOpenObservations({
362→    surreal,
363→    workspaceRecord,
364→    limit: 100,
365→  });
366→
367→  const [orphanedDecisions, staleObjectives] = await Promise.all([
368→    queryOrphanedDecisions(surreal, workspaceRecord),
369→    queryStaleObjectives(surreal, workspaceRecord),
370→  ]);
371→
372→  result.orphaned_decisions_found = orphanedDecisions.length;
373→  result.stale_objectives_found = staleObjectives.length;
374→
375→  // Create observations for orphaned decisions
376→  for (const decision of orphanedDecisions) {
377→    const existingForDecision = await queryExistingObserverObservationsForEntity(
378→      surreal,
379→      workspaceRecord,
380→      decision.id as RecordId<string, string>,
381→    );
382→
383→    const observationText =
384→      `Orphaned decision: "${decision.summary}" was confirmed but has no implementing task or commit ` +
385→      `after ${COHERENCE_AGE_THRESHOLD_DAYS} days. Consider creating implementation tasks or revisiting this decision.`;
386→
387→    if (
388→      existingForDecision.length > 0 ||
389→      isAlreadyObserved(existingObservations, observationText, decision.id.id as string)
390→    ) {
391→      logInfo("observer.coherence.dedup", "Skipping duplicate orphaned decision observation", {
392→        decisionId: decision.id.id,
393→      });
394→      continue;
395→    }
396→
397→    const now = new Date();
398→    await createObservation({
399→      surreal,
400→      workspaceRecord,
401→      text: observationText,
402→      severity: "warning",
403→      sourceAgent: "observer_agent",
404→      observationType: "anomaly",
405→      now,
406→      relatedRecords: [
407→        decision.id as ObserveTargetRecord,
408→      ],
409→    });
410→    result.observations_created += 1;
411→  }
412→
413→  // Create observations for stale objectives
414→  for (const objective of staleObjectives) {
415→    const existingForObjective = await queryExistingObserverObservationsForEntity(
416→      surreal,
417→      workspaceRecord,
418→      objective.id as RecordId<string, string>,
419→    );
420→
421→    const observationText =
422→      `Stale objective: "${objective.title}" has been active for over ${COHERENCE_AGE_THRESHOLD_DAYS} days ` +
423→      `with no supporting intents. Consider aligning work to this objective or archiving it.`;
424→
425→    if (
426→      existingForObjective.length > 0 ||
427→      isAlreadyObserved(existingObservations, observationText, objective.id.id as string)
428→    ) {
429→      logInfo("observer.coherence.dedup", "Skipping duplicate stale objective observation", {
430→        objectiveId: objective.id.id,
431→      });
432→      continue;
433→    }
434→
435→    const now = new Date();
436→    await createObservation({
437→      surreal,
438→      workspaceRecord,
439→      text: observationText,
440→      severity: "warning",
441→      sourceAgent: "observer_agent",
442→      observationType: "anomaly",
443→      now,
444→      relatedRecords: [
445→        objective.id as ObserveTargetRecord,
446→      ],
447→    });
448→    result.observations_created += 1;
449→  }
450→
451→  logInfo("observer.coherence.completed", "Coherence scan completed", {
452→    workspaceId: workspaceRecord.id,
453→    ...result,
454→  });
455→
456→  return result;
457→}
458→
459→// ---------------------------------------------------------------------------
460→// Scan orchestrator
461→// ---------------------------------------------------------------------------
462→
463→export async function runGraphScan(
464→  surreal: Surreal,
465→  workspaceRecord: RecordId<"workspace", string>,
466→  observerModel: LanguageModel,
467→  embeddingModel: EmbeddingModel,
468→  embeddingDimension: number,
469→): Promise<GraphScanResult> {
470→  const result: GraphScanResult = {
471→    contradictions_found: 0,
472→    stale_blocked_found: 0,
473→    status_drift_found: 0,
474→    orphaned_decisions_found: 0,
475→    stale_objectives_found: 0,
476→    observations_created: 0,
477→    llm_filtered_count: 0,
478→    learning_proposals_created: 0,
479→    clusters_found: 0,
480→    coverage_skips: 0,
481→    behavior_learning_proposals: 0,
482→  };
483→
484→  // Load existing observations for deduplication
485→  const existingObservations = await listWorkspaceOpenObservations({
486→    surreal,
487→    workspaceRecord,
488→    limit: 100,
489→  });
490→
491→  // 1. Detect decision-implementation contradictions (LLM-based)
492→  const [decisions, completedTasks] = await Promise.all([
493→    queryConfirmedDecisions(surreal, workspaceRecord),
494→    queryCompletedTasks(surreal, workspaceRecord),
495→  ]);
496→
497→  type ContradictionPair = { decision: ConfirmedDecision; task: CompletedTask };
498→  const contradictions: ContradictionPair[] = [];
499→
500→  if (decisions.length > 0 && completedTasks.length > 0) {
501→    const decisionMap = new Map(decisions.map((d) => [d.id.id as string, d]));
502→    const taskMap = new Map(completedTasks.map((t) => [t.id.id as string, t]));
503→
504→    const detected = await detectContradictions(
505→      observerModel,
506→      decisions.map((d) => ({ id: d.id.id as string, summary: d.summary, rationale: d.rationale })),
507→      completedTasks.map((t) => ({ id: t.id.id as string, title: t.title, description: t.description })),
508→    );
509→
510→    if (detected) {
511→      for (const c of detected) {
512→        const decisionId = parseEntityRef(c.decision_ref)?.id;
513→        const taskId = parseEntityRef(c.task_ref)?.id;
514→        const decision = decisionId ? decisionMap.get(decisionId) : undefined;
515→        const task = taskId ? taskMap.get(taskId) : undefined;
516→        if (decision && task) contradictions.push({ decision, task });
517→      }
518→    }
519→  }
520→
521→  result.contradictions_found = contradictions.length;
522→
523→  for (const { decision, task } of contradictions) {
524→    // Entity-level dedup: check if observer already has an open observation on this decision
525→    const existingForDecision = await queryExistingObserverObservationsForEntity(
526→      surreal, workspaceRecord,
527→      decision.id as RecordId<string, string>,
528→    );
529→
530→    const observationText =
531→      `Contradiction detected: Decision "${decision.summary}" conflicts with completed task "${task.title}". ` +
532→      `The task appears to implement an approach that contradicts the confirmed decision.`;
533→
534→    if (existingForDecision.length > 0 || isAlreadyObserved(existingObservations, observationText, decision.id.id as string)) {
535→      logInfo("observer.scan.dedup", "Skipping duplicate contradiction observation", {
536→        decisionId: decision.id.id,
537→        taskId: task.id.id,
538→      });
539→      continue;
540→    }
541→
542→    const now = new Date();
543→    await createObservation({
544→      surreal,
545→      workspaceRecord,
546→      text: observationText,
547→      severity: "conflict",
548→      sourceAgent: "observer_agent",
549→      observationType: "contradiction",
550→      now,
551→      relatedRecords: [
552→        decision.id as ObserveTargetRecord,
553→        task.id as ObserveTargetRecord,
554→      ],
555→    });
556→
557→    result.observations_created += 1;
558→  }
559→
560→  // 2. Detect stale blocked tasks and status drift (concurrent queries)
561→  const [staleBlocked, driftTasks] = await Promise.all([
562→    queryStaleBlockedTasks(surreal, workspaceRecord),
563→    queryStatusDriftTasks(surreal, workspaceRecord),
564→  ]);
565→  result.stale_blocked_found = staleBlocked.length;
566→  result.status_drift_found = driftTasks.length;
567→
568→  // 3. LLM anomaly evaluation: filter false positives before creating observations
569→  const anomalyCandidates: AnomalyCandidate[] = [];
570→
571→  for (const task of staleBlocked) {
572→    anomalyCandidates.push({
573→      entityRef: `task:${task.id.id as string}`,
574→      type: "stale_blocked",
575→      title: task.title,
576→      description: task.description,
577→      detail: `Blocked for ${task.daysBlocked} days since ${new Date(task.updated_at).toISOString().slice(0, 10)}`,
578→    });
579→  }
580→
581→  for (const drift of driftTasks) {
582→    anomalyCandidates.push({
583→      entityRef: `task:${drift.id.id as string}`,
584→      type: "status_drift",
585→      title: drift.title,
586→      description: undefined,
587→      detail: `Marked as ${drift.status} but dependency "${drift.dependency.title}" is still ${drift.dependency.status}`,
588→    });
589→  }
590→
591→  // Build evaluation map: entityRef -> LLM verdict (fallback: all relevant with default severity)
592→  const evaluationMap = new Map<string, { relevant: boolean; reasoning: string; severity: "info" | "warning" | "conflict" }>();
593→
594→  if (anomalyCandidates.length > 0) {
595→    const evaluations = await evaluateAnomalies(observerModel, anomalyCandidates);
596→
597→    if (evaluations) {
598→      for (const ev of evaluations) {
599→        evaluationMap.set(ev.entity_ref, {
600→          relevant: ev.relevant,
601→          reasoning: ev.reasoning,
602→          severity: ev.suggested_severity,
603→        });
604→      }
605→    } else {
606→      logInfo("observer.llm.fallback", "Anomaly evaluation failed, treating all as relevant", {
607→        candidateCount: anomalyCandidates.length,
608→      });
609→    }
610→  }
611→
612→  // Create observations for anomalies (stale-blocked + status-drift), LLM-filtered
613→  type AnomalyObservation = {
614→    entityRef: string;
615→    taskRecord: RecordId<"task">;
616→    observationText: string;
617→    anomalyType: string;
618→    dedupContext?: Record<string, unknown>;
619→  };
620→
621→  const anomalyObservations: AnomalyObservation[] = [
622→    ...staleBlocked.map((task): AnomalyObservation => {
623→      const llmReasoning = evaluationMap.get(`task:${task.id.id as string}`)?.reasoning;
624→      return {
625→        entityRef: `task:${task.id.id as string}`,
626→        taskRecord: task.id,
627→        anomalyType: "stale-blocked",
628→        observationText: llmReasoning
629→          ? `Task blocked for ${task.daysBlocked} days: "${task.title}". ${llmReasoning}`
630→          : `Task blocked for ${task.daysBlocked} days: "${task.title}". ` +
631→            `This task has been blocked since ${new Date(task.updated_at).toISOString().slice(0, 10)} ` +
632→            `(exceeds the ${STALE_BLOCKED_THRESHOLD_DAYS}-day threshold).`,
633→        dedupContext: { taskId: task.id.id },
634→      };
635→    }),
636→    ...driftTasks.map((drift): AnomalyObservation => {
637→      const llmReasoning = evaluationMap.get(`task:${drift.id.id as string}`)?.reasoning;
638→      return {
639→        entityRef: `task:${drift.id.id as string}`,
640→        taskRecord: drift.id,
641→        anomalyType: "status-drift",
642→        observationText: llmReasoning
643→          ? `Status drift: Task "${drift.title}" is ${drift.status} but dependency "${drift.dependency.title}" is ${drift.dependency.status}. ${llmReasoning}`
644→          : `Status drift detected: Task "${drift.title}" is marked as ${drift.status}, ` +
645→            `but its dependency "${drift.dependency.title}" is still ${drift.dependency.status}. ` +
646→            `A task should not be completed before its dependencies.`,
647→        dedupContext: { taskId: drift.id.id, depTaskId: drift.dependency.id.id },
648→      };
649→    }),
650→  ];
651→
652→  for (const anomaly of anomalyObservations) {
653→    const evaluation = evaluationMap.get(anomaly.entityRef);
654→
655→    if (evaluation && !evaluation.relevant) {
656→      logInfo("observer.scan.llm_filtered", `${anomaly.anomalyType} task filtered by LLM as not relevant`, {
657→        taskId: (anomaly.taskRecord.id as string),
658→        reasoning: evaluation.reasoning,
659→      });
660→      result.llm_filtered_count += 1;
661→      continue;
662→    }
663→
664→    const existingForTask = await queryExistingObserverObservationsForEntity(
665→      surreal, workspaceRecord,
666→      anomaly.taskRecord as RecordId<string, string>,
667→    );
668→
669→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, anomaly.observationText, anomaly.taskRecord.id as string)) {
670→      logInfo("observer.scan.dedup", `Skipping duplicate ${anomaly.anomalyType} observation`, anomaly.dedupContext ?? {});
671→      continue;
672→    }
673→
674→    const severity = evaluation?.severity ?? "warning";
675→    const now = new Date();
676→    await createObservation({
677→      surreal,
678→      workspaceRecord,
679→      text: anomaly.observationText,
680→      severity,
681→      sourceAgent: "observer_agent",
682→      observationType: "anomaly",
683→      now,
684→      relatedRecords: [anomaly.taskRecord as ObserveTargetRecord],
685→    });
686→
687→    result.observations_created += 1;
688→  }
689→
690→  // 4. LLM pattern synthesis
691→  const anomalies: Anomaly[] = [];
692→
693→  for (const { decision, task } of contradictions) {
694→    anomalies.push({
695→      type: "contradiction",
696→      text: `Decision "${decision.summary}" conflicts with task "${task.title}"`,
697→      entityId: decision.id.id as string,
698→      entityTable: "decision",
699→    });
700→    anomalies.push({
701→      type: "contradiction",
702→      text: `Task "${task.title}" contradicts decision "${decision.summary}"`,
703→      entityId: task.id.id as string,
704→      entityTable: "task",
705→    });
706→  }
707→  for (const task of staleBlocked) {
708→    const evaluation = evaluationMap.get(`task:${task.id.id as string}`);
709→    if (evaluation && !evaluation.relevant) continue; // skip LLM-filtered anomalies
710→    anomalies.push({
711→      type: "stale_blocked",
712→      text: `Task "${task.title}" blocked for ${task.daysBlocked} days`,
713→      entityId: task.id.id as string,
714→      entityTable: "task",
715→    });
716→  }
717→  for (const drift of driftTasks) {
718→    const evaluation = evaluationMap.get(`task:${drift.id.id as string}`);
719→    if (evaluation && !evaluation.relevant) continue; // skip LLM-filtered anomalies
720→    anomalies.push({
721→      type: "status_drift",
722→      text: `Task "${drift.title}" completed but dependency "${drift.dependency.title}" is ${drift.dependency.status}`,
723→      entityId: drift.id.id as string,
724→      entityTable: "task",
725→    });
726→  }
727→
728→  if (anomalies.length > 0) {
729→    const patterns = await synthesizePatterns(observerModel, anomalies);
730→
731→    if (patterns) {
732→      for (const pattern of patterns) {
733→        // Dedup: check if a similar pattern observation already exists
734→        const patternText = `${pattern.pattern_name}: ${pattern.description}`;
735→        if (isAlreadyObserved(existingObservations, patternText)) {
736→          logInfo("observer.scan.synthesis_dedup", "Skipping duplicate pattern", {
737→            pattern: pattern.pattern_name,
738→          });
739→          continue;
740→        }
741→
742→        // Build related records from contributing entities
743→        const relatedRecords: ObserveTargetRecord[] = [];
744→        for (const ref of pattern.contributing_entities) {
745→          const parsed = parseEntityRef(ref);
746→          if (parsed) {
747→            relatedRecords.push(new RecordId(parsed.table, parsed.id) as ObserveTargetRecord);
748→          }
749→        }
750→
751→        const now = new Date();
752→        await createObservation({
753→          surreal,
754→          workspaceRecord,
755→          text: patternText,
756→          severity: pattern.severity,
757→          sourceAgent: "observer_agent",
758→          observationType: "pattern",
759→          now,
760→          relatedRecords: relatedRecords.length > 0 ? relatedRecords : undefined,
761→        });
762→
763→        result.observations_created += 1;
764→      }
765→
766→      logInfo("observer.scan.synthesis", "Pattern synthesis completed", {
767→        patternsFound: patterns.length,
768→      });
769→    } else {
770→      logInfo("observer.llm.fallback", "Pattern synthesis failed, anomalies reported individually", {
771→        anomalyCount: anomalies.length,
772→      });
773→    }
774→  }
775→
776→  // 5. Coherence scans (deterministic, no LLM)
777→  const coherenceResult = await runCoherenceScans(surreal, workspaceRecord);
778→  result.orphaned_decisions_found = coherenceResult.orphaned_decisions_found;
779→  result.stale_objectives_found = coherenceResult.stale_objectives_found;
780→  result.observations_created += coherenceResult.observations_created;
781→
782→  // 6. Diagnostic learning proposals: cluster observations and check coverage
783→  try {
784→    const diagnostic = await runDiagnosticClustering(surreal, workspaceRecord, observerModel, embeddingModel, embeddingDimension);
785→    result.clusters_found = diagnostic.result.clusters_found;
786→    result.coverage_skips = diagnostic.result.coverage_skips;
787→    result.learning_proposals_created = diagnostic.result.learning_proposals_created;
788→
789→    logInfo("observer.scan.diagnostic", "Diagnostic clustering completed", {
790→      workspaceId: workspaceRecord.id,
791→      clustersFound: diagnostic.result.clusters_found,
792→      coverageSkips: diagnostic.result.coverage_skips,
793→      uncoveredClusters: diagnostic.uncoveredClusters.length,
794→    });
795→  } catch (error) {
796→    logInfo("observer.scan.diagnostic_error", "Diagnostic clustering failed, continuing scan", {
797→      workspaceId: workspaceRecord.id,
798→      error: error instanceof Error ? error.message : String(error),
799→    });
800→  }
801→
802→  // 7. Behavior trend learning proposals: detect drift/flat patterns, propose learnings
803→  try {
804→    const rateLimitCheck = await checkBehaviorLearningRateLimit({
805→      surreal,
806→      workspaceRecord,
807→    });
808→
809→    if (rateLimitCheck.blocked) {
810→      logInfo("observer.scan.behavior_rate_limited", "Behavior learning proposals rate-limited", {
811→        workspaceId: workspaceRecord.id,
812→        recentProposalCount: rateLimitCheck.count,
813→      });
814→    } else {
815→      const behaviorTrends = await queryWorkspaceBehaviorTrends(surreal, workspaceRecord);
816→      const actionableTrends = behaviorTrends.filter(
817→        (t) => t.trend.pattern === "drift" || (t.trend.pattern === "flat" && t.trend.belowThreshold),
818→      );
819→
820→      for (const trend of actionableTrends) {
821→        const proposalResult = await proposeBehaviorLearning({
822→          surreal,
823→          workspaceRecord,
824→          identityId: trend.identityId,
825→          metricType: trend.metricType,
826→          behaviorIds: trend.behaviorIds,
827→          trendPattern: trend.trend.pattern,
828→          now: new Date(),
829→        });
830→
831→        if (proposalResult.created) {
832→          result.behavior_learning_proposals += 1;
833→        }
834→      }
835→
836→      logInfo("observer.scan.behavior_trends", "Behavior trend analysis completed", {
837→        workspaceId: workspaceRecord.id,
838→        totalTrends: behaviorTrends.length,
839→        actionableTrends: actionableTrends.length,
840→        proposalsCreated: result.behavior_learning_proposals,
841→      });
842→    }
843→  } catch (error) {
844→    logInfo("observer.scan.behavior_error", "Behavior trend analysis failed, continuing scan", {
845→      workspaceId: workspaceRecord.id,
846→      error: error instanceof Error ? error.message : String(error),
847→    });
848→  }
849→
850→  logInfo("observer.scan.completed", "Graph scan completed", {
851→    workspaceId: workspaceRecord.id,
852→    ...result,
853→  });
854→
855→  return result;
856→}
