567→): Promise<Response> {
568→  return fetchRaw(
569→    `${baseUrl}/api/observe/scan/${workspaceId}`,
570→    {
571→      method: "POST",
572→      headers: { "Content-Type": "application/json", ...headers },
573→    },
574→  );
