 * Regression test: deduplicated anomalies must not leak into pattern synthesis.
 *
 * Before this fix, runGraphScan would skip creating duplicate anomaly observations
 * (entity-level dedup worked correctly) but still pass those anomalies to
 * synthesizePatterns(). The LLM would then create a "pattern" observation from
 * already-known anomalies, producing an unexpected extra observation.
 *
 * This test uses the injectable GraphScanLlm dependency to stub LLM calls and
 * capture the anomaly list passed to synthesizePatterns.
 */
import { describe, expect, it } from "bun:test";
import { RecordId } from "surrealdb";
import { setupAcceptanceSuite } from "../../acceptance/acceptance-test-kit";
import { createObservationByAgent, createTestUser, createTestWorkspace } from "../../acceptance/observer-agent/observer-test-kit";
import { runGraphScan, type GraphScanLlm } from "../../../app/src/server/observer/graph-scan";
import type { Anomaly } from "../../../app/src/server/observer/llm-synthesis";

const getRuntime = setupAcceptanceSuite("graph_scan_dedup_synthesis");

describe("graph scan dedup → synthesis filtering", () => {
  it("does not pass deduplicated stale-blocked anomalies to synthesizePatterns", async () => {
    const { surreal } = getRuntime();

    // Given a workspace with a stale blocked task
    const baseUrl = `http://127.0.0.1:${getRuntime().port}`;
    const user = await createTestUser(baseUrl, "dedup-synth");
    const workspace = await createTestWorkspace(baseUrl, user);

    const taskId = `task-${crypto.randomUUID()}`;
    const taskRecord = new RecordId("task", taskId);
    const wsRecord = new RecordId("workspace", workspace.workspaceId);

    const fifteenDaysAgo = new Date(Date.now() - 15 * 24 * 60 * 60 * 1000);
    await surreal.query(`CREATE $task CONTENT $content;`, {
      task: taskRecord,
      content: {
        title: "Stale task for dedup regression",
        status: "blocked",
        workspace: wsRecord,
        created_at: fifteenDaysAgo,
        updated_at: fifteenDaysAgo,
      },
    });

    // And the observer has already flagged this task
    await createObservationByAgent(surreal, workspace.workspaceId, "observer_agent", {
      text: "Task blocked for over 14 days: Stale task for dedup regression",
      severity: "warning",
      observationType: "anomaly",
      targetTable: "task",
      targetId: taskId,
    });

    // Capture what synthesizePatterns receives
    let capturedAnomalies: Anomaly[] | undefined;

    const stubLlm: GraphScanLlm = {
      detectContradictions: async () => [],
      evaluateAnomalies: async (_model, candidates) =>
        candidates.map((c) => ({
          entity_ref: c.entityRef,
          relevant: true,
          reasoning: "Test stub: marked relevant",
          suggested_severity: "warning" as const,
        })),
      synthesizePatterns: async (_model, anomalies) => {
        capturedAnomalies = anomalies;
        return [];
      },
    };

    // When runGraphScan executes with stubbed LLM
    const result = await runGraphScan(
      surreal,
      wsRecord,
      {} as never, // observerModel unused by stubs
      {} as never, // embeddingModel unused (diagnostic clustering will fail gracefully)
      1536,
      stubLlm,
    );

    // Then the stale-blocked task was found
    expect(result.stale_blocked_found).toBe(1);

    // And no duplicate observation was created
    expect(result.observations_created).toBe(0);

    // And the deduplicated anomaly was NOT passed to synthesizePatterns.
    // synthesizePatterns is either not called (anomalies list empty after filtering)
    // or called with an empty/filtered list that excludes the deduped entity.
    const staleBlockedInSynthesis = (capturedAnomalies ?? []).filter(
      (a) => a.type === "stale_blocked" && a.entityId === taskId,
    );
    expect(staleBlockedInSynthesis).toHaveLength(0);
  }, 30_000);
});

